+		} else {
+			for i, step := range response.Steps {
+				line := directionsStepLine(step)
+				if line == "" {
+					continue
+				}
+				out.WriteString(fmt.Sprintf("  %d. %s\n", i+1, line))
+			}
+		}
+	}
+	return out.String()
